+    robot: bool,
+) -> OutputFormat {
+    if json || robot {
+        OutputFormat::Json
+    } else if let Some(requested) = requested {
+        requested
+    } else {
+        OutputFormat::from_env().unwrap_or(OutputFormat::Text)
+    }
+}
